import subprocess
import sys
import os
import shutil

REQUIREMENTS_FILE = "requirements.txt"
TEST_COMMAND = [sys.executable, "-m", "pytest", "tests/"] # Assuming tests are in a 'tests' directory
PACKAGE_DIR = "dist"
APP_NAME = "my_application" # Replace with your application's main module or directory

def install_dependencies():
    print(f"Installing dependencies from {REQUIREMENTS_FILE}...")
    try:
        subprocess.run([sys.executable, "-m", "pip", "install", "-r", REQUIREMENTS_FILE], check=True, capture_output=True, text=True)
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error installing dependencies: {e.stderr}")
        sys.exit(1)

def run_tests():
    print("Running application tests...")
    try:
        subprocess.run(TEST_COMMAND, check=True)
        print("Tests passed successfully.")
    except subprocess.CalledProcessError:
        print("Tests failed.")
        sys.exit(1)

def package_for_deployment():
    print("Packaging application for deployment...")

    if os.path.exists(PACKAGE_DIR):
        shutil.rmtree(PACKAGE_DIR)
    os.makedirs(PACKAGE_DIR)

    # Example packaging: Copy necessary files to the package directory
    # Customize this based on your application structure
    try:
        # Copy the main application code
        if os.path.isdir(APP_NAME):
            shutil.copytree(APP_NAME, os.path.join(PACKAGE_DIR, APP_NAME))
        elif os.path.isfile(f"{APP_NAME}.py"):
            shutil.copy2(f"{APP_NAME}.py", PACKAGE_DIR)
        else:
            print(f"Warning: Application source '{APP_NAME}' not found. Adjust packaging logic.")

        # Copy requirements file (useful for containerization or remote installs)
        if os.path.exists(REQUIREMENTS_FILE):
            shutil.copy2(REQUIREMENTS_FILE, PACKAGE_DIR)

        # You might also copy:
        # - Configuration files (e.g., config.ini, .env.prod)
        # - Static assets (e.g., static/, templates/)
        # - Database migrations (e.g., migrations/)
        # - Dockerfile if you're building an image

        print(f"Application packaged into '{PACKAGE_DIR}' directory.")
    except Exception as e:
        print(f"Error during packaging: {e}")
        sys.exit(1)

def main():
    print("Starting production deployment workflow...")
    install_dependencies()
    run_tests()
    package_for_deployment()
    print("Deployment workflow completed successfully.")

if __name__ == "__main__":
    main()